fn generate_mime_type(rng: &mut impl Rng) -> Value {
    let types = [
        "text/plain", "application/json", "image/png", "text/html",
        "application/octet-stream", "multipart/form-data",
    ];
    let idx = rng.random_range(0..types.len());
