    // -------------------------------------------------------------------
    // Property-based tests
    // -------------------------------------------------------------------

    mod prop_tests {
        use super::*;
        use proptest::prelude::*;
        use serde_json::json;

        proptest! {
            #[test]
            fn shrink_never_contains_original_int(n in any::<i64>()) {
                let val = json!(n);
