        let mut saw_value = false;
        for _ in 0..100 {
            let mutated = mutate_value(&json!(42), &typ, &[], &mut rng);
            if mutated.is_null() {
                saw_null = true;
            } else {
                saw_value = true;
            }
        }
        assert!(saw_null, "should sometimes flip to null");
        assert!(saw_value, "should sometimes keep/mutate value");
    }

