            ParamInfo { name: "a".into(), typ: TypeInfo::Int, type_name: None },
            ParamInfo { name: "b".into(), typ: TypeInfo::Str, type_name: None },
            ParamInfo { name: "c".into(), typ: TypeInfo::Bool, type_name: None },
