    fn crossover_inputs_object_field_level() {
        let params = vec![ParamInfo {
            name: "obj".into(),
            typ: TypeInfo::Object {
                fields: vec![
                    ("x".into(), TypeInfo::Int),
                    ("y".into(), TypeInfo::Int),
                    ("z".into(), TypeInfo::Int),
                ],
