    let choice: u8 = rng.random_range(0..5);
    let v: u8 = match choice {
        0 => 0,
        1 => 1,
        2 => 127,
        3 => 255,
        _ => rng.random_range(0..=255),
    };
    json!({"__complex_type": "go_byte", "value": v})
}

